// Compute median price for this route from historical data in Firestore
// (stub: in production, query Firestore for last 90 days)
// For MVP, use static baseline from CSV

const MEDIANS = {
  'BEG-IST': { may: 205, jun: 240, jul: 310, aug: 295, oct: 180 },
  'BEG-FCO': { may: 140, jun: 180, jul: 220, aug: 210, oct: 144 },
  'BEG-SKG': { may: 160, jun: 200, jul: 280, aug: 270, oct: 150 },
  'BEG-BCN': { may: 180, jun: 220, jul: 260, aug: 250, oct: 180, sep: 223 },
  'BEG-CDG': { may: 165, jun: 195, jul: 235, aug: 230, oct: 170, nov: 186 },
  'BEG-DXB': { feb: 832, may: 650, nov: 620, dec: 780 },
  'BEG-BUD': { may: 85, jun: 105, jul: 130 },
  'BEG-VIE': { may: 95, jun: 120, jul: 145 },
  'BEG-PRG': { may: 110, jun: 130, jul: 160 },
  'BEG-AMS': { may: 170, jun: 195, jul: 230 }
};

const MONTH_NAMES = ['jan', 'feb', 'mar', 'apr', 'may', 'jun', 'jul', 'aug', 'sep', 'oct', 'nov', 'dec'];

const routeKey = `${$input.first().json.from}-${$input.first().json.to}`;
const kiwiData = $input.last().json.data || [];

if (!kiwiData.length) {
  return [];
}

// Find cheapest flight in next 90 days
const cheapest = kiwiData.reduce((min, f) => f.price < min.price ? f : min, kiwiData[0]);
const depDate = new Date(cheapest.local_departure);
const monthIdx = depDate.getMonth();
const monthKey = MONTH_NAMES[monthIdx];

const median = MEDIANS[routeKey]?.[monthKey];
if (!median) return [];

const discount = ((median - cheapest.price) / median) * 100;

// Only flag if 30%+ below median
if (discount < 30) return [];

return [{
  json: {
    routeKey,
    routeName: $input.first().json.name,
    from: $input.first().json.from,
    to: $input.first().json.to,
    price: Math.round(cheapest.price),
    medianPrice: median,
    discount: Math.round(discount),
    departureDate: cheapest.local_departure,
    returnDate: cheapest.local_arrival,
    airline: cheapest.airlines?.[0] || 'Multiple',
    bookingLink: cheapest.deep_link,
    flightDuration: cheapest.duration?.total,
    month: monthKey,
    year: depDate.getFullYear()
  }
}];

// Merge deal data with generated blurb
const deal = $('deal-detector').item.json;
const blurb = $input.first().json.text || $input.first().json.content || '';

return [{
  json: {
    ...deal,
    blurb: blurb.trim(),
    createdAt: new Date().toISOString(),
    status: 'pending_review', // requires human approval before publish
    id: `deal_${Date.now()}_${deal.routeKey}`
  }
}];

